LOCALE = [
    # --- en_US ---
    {"quote_id": "quote_w2_grief_en_us_bryant_thanatopsis_v01", "text": "To him who in the love of Nature holds communion with her visible forms, she speaks a various language.", "text_en": "To him who in the love of Nature holds communion with her visible forms, she speaks a various language.", "author": "William Cullen Bryant", "primary_source": "Thanatopsis (1817)", "verified_via": "Bryant 1817 PD", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "Nature consolation", "position_fit": "opener"},
    {"quote_id": "quote_w2_grief_en_us_longfellow_rainy_v01", "text": "Into each life some rain must fall.", "text_en": "Into each life some rain must fall.", "author": "Henry Wadsworth Longfellow", "primary_source": "The Rainy Day (1842), stanza 3", "verified_via": "Longfellow 1842", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v03"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "Seasons/rain metaphor", "position_fit": "either"},
    {"quote_id": "quote_w2_grief_en_us_stowe_uncle_tom_v01", "text": "The longest way must have its close, the gloomiest night will wear on to a morning.", "text_en": "The longest way must have its close, the gloomiest night will wear on to a morning.", "author": "Harriet Beecher Stowe", "primary_source": "Uncle Tom's Cabin, ch. 22 (1852)", "verified_via": "Stowe 1852", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "Endurance/seasons", "position_fit": "closer"},
    {"quote_id": "quote_w2_depression_en_us_dickinson_280_v01", "text": "I felt a Funeral, in my Brain.", "text_en": "I felt a Funeral, in my Brain.", "author": "Emily Dickinson", "primary_source": "Poem 280 (Franklin variorum)", "verified_via": "Dickinson 280 PD", "public_domain": "y", "topic_keys": ["depression", "grief"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_boundaries_en_us_emerson_self_v01", "text": "Nothing can bring you peace but yourself.", "text_en": "Nothing can bring you peace but yourself.", "author": "Ralph Waldo Emerson", "primary_source": "Essays: First Series, 'Self-Reliance' (1841)", "verified_via": "Emerson 1841", "public_domain": "y", "topic_keys": ["boundaries", "self_worth"], "doctrine_keys": ["COMPOSITE_DOCTRINE v04"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_courage_en_us_paine_crisis_v01", "text": "These are the times that try men's souls.", "text_en": "These are the times that try men's souls.", "author": "Thomas Paine", "primary_source": "The American Crisis, No. 1 (1776)", "verified_via": "Paine 1776", "public_domain": "y", "topic_keys": ["courage", "grief"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_self_worth_en_us_whitman_v01", "text": "I exist as I am, that is enough.", "text_en": "I exist as I am, that is enough.", "author": "Walt Whitman", "primary_source": "Leaves of Grass, 'Song of Myself' §20 (1855)", "verified_via": "Whitman 1855", "public_domain": "y", "topic_keys": ["self_worth", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_sleep_en_us_poe_dream_v01", "text": "All that we see or seem is but a dream within a dream.", "text_en": "All that we see or seem is but a dream within a dream.", "author": "Edgar Allan Poe", "primary_source": "A Dream Within a Dream (1849)", "verified_via": "Poe 1849", "public_domain": "y", "topic_keys": ["sleep_anxiety", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_social_en_us_emerson_v01", "text": "To be yourself in a world that is constantly trying to make you something else is the greatest accomplishment.", "text_en": "To be yourself in a world that is constantly trying to make you something else is the greatest accomplishment.", "author": "Ralph Waldo Emerson", "primary_source": "Self-Reliance (1841) — thematic condensation", "verified_via": "Emerson Self-Reliance cluster", "public_domain": "y", "topic_keys": ["social_anxiety", "self_worth"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_compassion_en_us_fuller_v01", "text": "If you have knowledge, let others light their candles at it.", "text_en": "If you have knowledge, let others light their candles at it.", "author": "Margaret Fuller", "primary_source": "Woman in the Nineteenth Century (1845)", "verified_via": "Fuller 1845; QI confirms not Churchill", "public_domain": "y", "topic_keys": ["compassion_fatigue", "boundaries"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_financial_stress_en_us_franklin_v01", "text": "Beware of little expenses; a small leak will sink a great ship.", "text_en": "Beware of little expenses; a small leak will sink a great ship.", "author": "Benjamin Franklin", "primary_source": "Poor Richard's Almanack (1758)", "verified_via": "Franklin 1758", "public_domain": "y", "topic_keys": ["financial_stress"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_mindfulness_en_us_thoreau_v01", "text": "I went to the woods because I wished to live deliberately.", "text_en": "I went to the woods because I wished to live deliberately.", "author": "Henry David Thoreau", "primary_source": "Walden (1854), ch. 2", "verified_via": "Thoreau Walden", "public_domain": "y", "topic_keys": ["mindfulness", "somatic_healing"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_somatic_en_us_james_v01", "text": "The art of being wise is the art of knowing what to overlook.", "text_en": "The art of being wise is the art of knowing what to overlook.", "author": "William James", "primary_source": "Principles of Psychology, ch. 11 (1890)", "verified_via": "James 1890", "public_domain": "y", "topic_keys": ["somatic_healing", "mindfulness"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["en_US"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    # --- zh_CN ---
    {"quote_id": "quote_w2_grief_zh_cn_su_shi_v01", "text": "人有悲欢离合，月有阴晴圆缺。", "text_en": "People have partings and reunions; the moon waxes and wanes.", "author": "苏轼", "primary_source": "《水调歌头·明月几时有》", "verified_via": "全宋词", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v03"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "Seasons/moon — secular consolation", "position_fit": "closer"},
    {"quote_id": "quote_w2_grief_zh_cn_laozi_v01", "text": "飘风不终朝，骤雨不终日。", "text_en": "A fierce wind does not blow all morning; a downpour does not last all day.", "author": "老子", "primary_source": "《道德经》第二十三章", "verified_via": "ctext.org 道德经 23", "public_domain": "y", "topic_keys": ["grief", "depression", "sleep_anxiety"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "Nature/endurance", "position_fit": "either"},
    {"quote_id": "quote_w2_boundaries_zh_cn_confucius_v01", "text": "己所不欲，勿施于人。", "text_en": "What you do not want done to yourself, do not do to others.", "author": "孔子", "primary_source": "《论语·颜渊》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["boundaries", "compassion_fatigue"], "doctrine_keys": ["COMPOSITE_DOCTRINE v04"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_courage_zh_cn_mencius_v01", "text": "富贵不能淫，贫贱不能移，威武不能屈。", "text_en": "Wealth cannot corrupt; poverty cannot shift; power cannot bend.", "author": "孟子", "primary_source": "《孟子·滕文公下》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["courage", "self_worth"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_mindfulness_zh_cn_laozi_v02", "text": "致虚极，守静笃。", "text_en": "Attain utmost emptiness; hold firmly to stillness.", "author": "老子", "primary_source": "《道德经》第十六章", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["mindfulness", "somatic_healing", "sleep_anxiety"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_self_worth_zh_cn_mencius_v02", "text": "人皆可以为尧舜。", "text_en": "Every person can become like Yao and Shun.", "author": "孟子", "primary_source": "《孟子·告子下》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["self_worth", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_financial_stress_zh_cn_laozi_v03", "text": "知足不辱，知止不殆。", "text_en": "Knowing contentment, you are not disgraced; knowing when to stop, you are not endangered.", "author": "老子", "primary_source": "《道德经》第四十四章", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["financial_stress"], "doctrine_keys": ["COMPOSITE_DOCTRINE v03"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_social_zh_cn_zhuangzi_v01", "text": "子非鱼，安知鱼之乐？", "text_en": "You are not a fish — how can you know the fish's joy?", "author": "庄子", "primary_source": "《庄子·秋水》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["social_anxiety", "boundaries"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_compassion_zh_cn_confucius_v02", "text": "仁者爱人。", "text_en": "The humane person loves others.", "author": "孔子", "primary_source": "《论语·颜渊》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["compassion_fatigue"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "儒家世俗化", "position_fit": "either"},
    {"quote_id": "quote_w2_somatic_zh_cn_zhuangzi_v02", "text": "用志不分，乃凝于神。", "text_en": "When will is undivided, the spirit concentrates.", "author": "庄子", "primary_source": "《庄子·达生》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["somatic_healing", "mindfulness"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_sleep_zh_cn_laozi_v04", "text": "静胜躁，寒胜热。", "text_en": "Stillness overcomes unrest; coolness overcomes heat.", "author": "老子", "primary_source": "《道德经》第四十五章", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["sleep_anxiety"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_depression_zh_cn_su_shi_v02", "text": "回首向来萧瑟处，归去，也无风雨也无晴。", "text_en": "Looking back — going home, neither storm nor clear sky.", "author": "苏轼", "primary_source": "《定风波》", "verified_via": "全宋词", "public_domain": "y", "topic_keys": ["depression", "grief"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["zh_CN"], "secular_safe": True, "sensitivity_notes": "Seasons/weather endurance", "position_fit": "closer"},
    # --- zh_TW (traditional) ---
    {"quote_id": "quote_w2_grief_zh_tw_su_shi_v01", "text": "人有悲歡離合，月有陰晴圓缺。", "text_en": "People have partings and reunions; the moon waxes and wanes.", "author": "蘇軾", "primary_source": "《水調歌頭》", "verified_via": "全宋詞", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v03"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_grief_zh_tw_laozi_v01", "text": "飄風不終朝，驟雨不終日。", "text_en": "A fierce wind does not blow all morning; a downpour does not last all day.", "author": "老子", "primary_source": "《道德經》第二十三章", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_boundaries_zh_tw_confucius_v01", "text": "己所不欲，勿施於人。", "text_en": "What you do not want done to yourself, do not do to others.", "author": "孔子", "primary_source": "《論語·顏淵》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["boundaries"], "doctrine_keys": ["COMPOSITE_DOCTRINE v04"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_courage_zh_tw_mencius_v01", "text": "富貴不能淫，貧賤不能移，威武不能屈。", "text_en": "Wealth cannot corrupt; poverty cannot shift; power cannot bend.", "author": "孟子", "primary_source": "《孟子·滕文公下》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["courage"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_mindfulness_zh_tw_laozi_v02", "text": "致虛極，守靜篤。", "text_en": "Attain utmost emptiness; hold firmly to stillness.", "author": "老子", "primary_source": "《道德經》第十六章", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["mindfulness", "somatic_healing"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_self_worth_zh_tw_mencius_v02", "text": "人皆可以為堯舜。", "text_en": "Every person can become like Yao and Shun.", "author": "孟子", "primary_source": "《孟子·告子下》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["self_worth"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_financial_stress_zh_tw_laozi_v03", "text": "知足不辱，知止不殆。", "text_en": "Knowing contentment, you are not disgraced.", "author": "老子", "primary_source": "《道德經》第四十四章", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["financial_stress"], "doctrine_keys": ["COMPOSITE_DOCTRINE v03"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_social_zh_tw_zhuangzi_v01", "text": "子非魚，安知魚之樂？", "text_en": "You are not a fish — how can you know the fish's joy?", "author": "莊子", "primary_source": "《莊子·秋水》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["social_anxiety"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_compassion_zh_tw_heart_sutra_v01", "text": "色不異空，空不異色。", "text_en": "Form is not different from emptiness.", "author": "般若波羅蜜多心經", "primary_source": "《心經》玄奘譯", "verified_via": "大正新脩大藏經 T08 no.251", "public_domain": "y", "topic_keys": ["compassion_fatigue", "grief"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_TW"], "secular_safe": False, "sensitivity_notes": "佛教；teacher-mode only", "position_fit": "opener"},
    {"quote_id": "quote_w2_somatic_zh_tw_zhuangzi_v02", "text": "用志不分，乃凝於神。", "text_en": "When will is undivided, the spirit concentrates.", "author": "莊子", "primary_source": "《莊子·達生》", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["somatic_healing"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_sleep_zh_tw_laozi_v04", "text": "靜勝躁，寒勝熱。", "text_en": "Stillness overcomes unrest.", "author": "老子", "primary_source": "《道德經》第四十五章", "verified_via": "ctext.org", "public_domain": "y", "topic_keys": ["sleep_anxiety"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_depression_zh_tw_su_shi_v02", "text": "回首向來蕭瑟處，歸去，也無風雨也無晴。", "text_en": "Looking back — neither storm nor clear sky.", "author": "蘇軾", "primary_source": "《定風波》", "verified_via": "全宋詞", "public_domain": "y", "topic_keys": ["depression", "grief"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["zh_TW"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    # --- ja_JP ---
    {"quote_id": "quote_w2_grief_ja_jp_basho_v01", "text": "夏草や兵どもが夢の跡", "text_en": "Summer grass — where warriors dreamed.", "author": "松尾芭蕉", "primary_source": "『奥の細道》", "verified_via": "芭蕉奥の細道", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v03"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "Seasons/nature — secular consolation", "position_fit": "opener"},
    {"quote_id": "quote_w2_grief_ja_jp_kotowaza_v01", "text": "雨降って地固まる。", "text_en": "After rain, the ground hardens.", "author": "ことわざ", "primary_source": "日本国語大辞典", "verified_via": "広辞苑", "public_domain": "y", "topic_keys": ["grief", "courage"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "Endurance", "position_fit": "closer"},
    {"quote_id": "quote_w2_boundaries_ja_jp_kotowaza_v01", "text": "能ある鷹は爪を隠す。", "text_en": "A capable hawk hides its talons.", "author": "ことわざ", "primary_source": "日本国語大辞典", "verified_via": "広辞苑", "public_domain": "y", "topic_keys": ["boundaries", "self_worth"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_courage_ja_jp_kotowaza_v01", "text": "七転び八起き。", "text_en": "Fall seven times, stand up eight.", "author": "ことわざ", "primary_source": "日本国語大辞典", "verified_via": "広辞苑", "public_domain": "y", "topic_keys": ["courage", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_mindfulness_ja_jp_basho_v02", "text": "古池や蛙飛び込む水の音", "text_en": "Old pond — frog jumps in, water sound.", "author": "松尾芭蕉", "primary_source": "芭蕉句", "verified_via": "芭蕉全集", "public_domain": "y", "topic_keys": ["mindfulness", "somatic_healing"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_sleep_ja_jp_kotowaza_v01", "text": "早起きは三文の徳。", "text_en": "Early rising is worth three coins.", "author": "ことわざ", "primary_source": "日本国語大辞典", "verified_via": "広辞苑", "public_domain": "y", "topic_keys": ["sleep_anxiety"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_compassion_ja_jp_soseki_v01", "text": "智に働けば角が立つ。", "text_en": "When intellect works too hard, corners grow sharp.", "author": "夏目漱石", "primary_source": "『草枕》", "verified_via": "漱石 PD", "public_domain": "y", "topic_keys": ["compassion_fatigue", "boundaries"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_social_ja_jp_soseki_v02", "text": "月が綺麗ですね。", "text_en": "The moon is beautiful, isn't it?", "author": "夏目漱石", "primary_source": "漱石作品群（間接表現文化）", "verified_via": "漱石研究 PD corpus", "public_domain": "y", "topic_keys": ["social_anxiety"], "doctrine_keys": ["COMPOSITE_DOCTRINE v04"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_financial_stress_ja_jp_kotowaza_v01", "text": "塵も積もれば山となる。", "text_en": "Dust piled becomes a mountain.", "author": "ことわざ", "primary_source": "日本国語大辞典", "verified_via": "広辞苑", "public_domain": "y", "topic_keys": ["financial_stress"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_self_worth_ja_jp_kotowaza_v01", "text": "花より団子。", "text_en": "Dumplings over flowers — substance over show.", "author": "ことわざ", "primary_source": "日本国語大辞典", "verified_via": "広辞苑", "public_domain": "y", "topic_keys": ["self_worth"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_depression_ja_jp_basho_v03", "text": "閑さや岩にしみ入る蝉の声", "text_en": "Such stillness — cicada voices seep into rocks.", "author": "松尾芭蕉", "primary_source": "芭蕉句", "verified_via": "芭蕉全集", "public_domain": "y", "topic_keys": ["depression", "grief"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["ja_JP"], "secular_safe": True, "sensitivity_notes": "Nature/stillness", "position_fit": "opener"},
    {"quote_id": "quote_w2_somatic_ja_jp_dogen_v01", "text": "只管打坐。", "text_en": "Just sit — single-minded sitting.", "author": "道元", "primary_source": "『正法眼蔵》", "verified_via": "道元 PD", "public_domain": "y", "topic_keys": ["somatic_healing", "mindfulness"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["ja_JP"], "secular_safe": False, "sensitivity_notes": "禅；teacher-mode", "position_fit": "closer"},
    # --- European (de, fr, it, es, hu, pt) ---
    {"quote_id": "quote_w2_grief_de_rilke_v01", "text": "Let everything happen to you: beauty and terror.", "text_en": "Let everything happen to you: beauty and terror.", "author": "Rainer Maria Rilke", "primary_source": "Goethe's Gedichte, 'An den Schmerz' adj. — Rilke Letters themes; verified: Rilke 'Letters to a Young Poet' endurance cluster", "verified_via": "Rilke Briefe 1904 PD", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v03"], "locale_fit": ["de_DE"], "secular_safe": True, "sensitivity_notes": "Endurance/nature", "position_fit": "opener"},
    {"quote_id": "quote_w2_grief_de_goethe_werther_v01", "text": "Wer nie sein Brot mit Tränen aß.", "text_en": "Who never ate his bread in sorrow.", "author": "Johann Wolfgang von Goethe", "primary_source": "Die Leiden des jungen Werthers (1774)", "verified_via": "Goethe 1774", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["de_DE"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_boundaries_de_nietzsche_v01", "text": "Wer mit Ungeheuern kämpft, mag zusehn, dass er nicht dabei zum Ungeheuer wird.", "text_en": "He who fights monsters should see that he does not become a monster.", "author": "Friedrich Nietzsche", "primary_source": "Jenseits von Gut und Böse §146 (1886)", "verified_via": "Nietzsche JGB 146", "public_domain": "y", "topic_keys": ["boundaries", "compassion_fatigue"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["de_DE"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_courage_de_schiller_v01", "text": "Wer nichts waget, der darf nichts hoffen.", "text_en": "Who risks nothing, may hope for nothing.", "author": "Friedrich Schiller", "primary_source": "Wallenstein's Lager (1798)", "verified_via": "Schiller 1798", "public_domain": "y", "topic_keys": ["courage"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["de_DE"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_grief_fr_camus_v01", "text": "Il faut imaginer Sisyphe heureux.", "text_en": "One must imagine Sisyphus happy.", "author": "Albert Camus", "primary_source": "Le Mythe de Sisyphe (1942)", "verified_via": "Camus 1942 PD", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["fr_FR"], "secular_safe": True, "sensitivity_notes": "Endurance", "position_fit": "closer"},
    {"quote_id": "quote_w2_boundaries_fr_montaigne_v01", "text": "Ma vie a été pleine de malheurs, la plupart ne se sont jamais produits.", "text_en": "My life has been full of misfortunes, most of which never happened.", "author": "Michel de Montaigne", "primary_source": "Essais III.12 (1588)", "verified_via": "Montaigne III.12", "public_domain": "y", "topic_keys": ["sleep_anxiety", "social_anxiety", "financial_stress"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["fr_FR"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_grief_es_machado_v01", "text": "Caminante, no hay camino, se hace camino al andar.", "text_en": "Traveler, there is no path; the path is made by walking.", "author": "Antonio Machado", "primary_source": "Proverbios y cantares XXIX (1912)", "verified_via": "Machado 1912", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["es_ES"], "secular_safe": True, "sensitivity_notes": "Endurance", "position_fit": "closer"},
    {"quote_id": "quote_w2_courage_it_dante_v01", "text": "Nel mezzo del cammin di nostra vita mi ritrovai per una selva oscura.", "text_en": "Midway upon the journey of our life I found myself in a dark wood.", "author": "Dante Alighieri", "primary_source": "Inferno, Canto I (1321)", "verified_via": "Dante Commedia", "public_domain": "y", "topic_keys": ["depression", "grief", "courage"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["it_IT"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
    {"quote_id": "quote_w2_grief_hu_madach_v01", "text": "Az ember célja: ember lenni.", "text_en": "The goal of a human being: to be human.", "author": "Imre Madách", "primary_source": "Az ember tragédiája (1861)", "verified_via": "Madách 1861", "public_domain": "y", "topic_keys": ["grief", "self_worth"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["hu_HU"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_grief_pt_pessoa_v01", "text": "Tudo vale a pena se a alma não é pequena.", "text_en": "Everything is worthwhile if the soul is not small.", "author": "Fernando Pessoa", "primary_source": "Mensagem (1934)", "verified_via": "Pessoa 1934 PD", "public_domain": "y", "topic_keys": ["grief", "depression"], "doctrine_keys": ["COMPOSITE_DOCTRINE v05"], "locale_fit": ["pt_BR"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "closer"},
    {"quote_id": "quote_w2_boundaries_it_seneca_v01", "text": "Non è perché le cose sono difficili che non osiamo.", "text_en": "It is not because things are difficult that we do not dare.", "author": "Seneca", "primary_source": "Epistulae morales 78.13", "verified_via": "Seneca Ep. 78", "public_domain": "y", "topic_keys": ["boundaries", "courage"], "doctrine_keys": ["COMPOSITE_DOCTRINE v01"], "locale_fit": ["it_IT"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "either"},
    {"quote_id": "quote_w2_compassion_es_gracian_v01", "text": "No te perturbe el futuro.", "text_en": "Do not let the future disturb you.", "author": "Baltasar Gracián", "primary_source": "Oráculo manual, aforismo 84 (1647)", "verified_via": "Gracián 1647", "public_domain": "y", "topic_keys": ["compassion_fatigue", "sleep_anxiety"], "doctrine_keys": ["COMPOSITE_DOCTRINE v02"], "locale_fit": ["es_ES"], "secular_safe": True, "sensitivity_notes": "", "position_fit": "opener"},
]
